public class BubbleSort {
	public static void bubbleSort(int[] arr) {
		for (int i = arr.length - 1; i >= 1; i--) {
			for (int j = 0; j < i; j++) {
				if (arr[j] > arr[j+1]) {
					int t = arr[j];
					arr[j] = arr[j+1];
					arr[j+1] = t;
				}
			}
		}
	}
	public static void main(String[] args) {
		int[] arr = {5, 3, 2, 4, 1};
		bubbleSort(arr);
	}
}

